import { describe, expect, it } from '@a0n/gnosis/test';
import {
  ceramicShatter,
  distributeForce,
  evaluateBallisticVestPosture,
  kineticDemand,
  residualReserve,
} from './ballistic-vest-policy.ts';

describe('ballistic vest policy mirror', () => {
  it('matches the concrete dense witness from BallisticVest.lean', () => {
    const wave = { mass: 2, velocitySquared: 100, localization: 4 };
    const vest = {
      fiberDensity: 9,
      bettiReserve: 250,
      dampingCoefficient: 8,
    };

    expect(kineticDemand(wave)).toBe(200);
    expect(distributeForce(wave, vest)).toBe(10);
    expect(residualReserve(wave, vest)).toBe(50);

    const posture = evaluateBallisticVestPosture(wave, vest);
    expect(posture.verdict).toBe('admit');
    expect(posture.reservePositive).toBe(true);
    expect(posture.loadReducedByWeave).toBe(true);
    expect(posture.ceramic.distributedLoad).toBeLessThanOrEqual(
      posture.distributedLoad,
    );
  });

  it('models ceramic shatter as delocalizing and velocity-reducing', () => {
    const wave = { mass: 3, velocitySquared: 77, localization: 5 };

    const shattered = ceramicShatter(wave);

    expect(shattered.localization).toBe(0);
    expect(shattered.velocitySquared).toBe(7);
    expect(shattered.velocitySquared).toBeLessThan(wave.velocitySquared);
  });
});
